import { Component, Host, Prop, h } from '@stencil/core';
import { Icons } from '../../assets/icons';
import { IconType } from '../../interface';

@Component({
  tag: 'cpsl-alert',
  styleUrl: 'cpsl-alert.scss',
  shadow: true,
})
export class CpslAlert {
  /**
   * The type of alert.
   * Options are: `"error"`
   * Default is: `"error"`.
   */
  @Prop() type?: 'error' = 'error';

  /**
   * The name of the icon to show.
   */
  @Prop() icon?: IconType;

  private get Icon() {
    if (Boolean(this.icon)) {
      return Icons[this.icon];
    }

    switch (this.type) {
      case 'error':
      default: {
        return Icons.alertCircle;
      }
    }
  }

  render() {
    return (
      <Host class={{ error: this.type === 'error' }}>
        <div class="alert-container">
          <div class="icon" innerHTML={this.Icon} />
          <slot></slot>
        </div>
      </Host>
    );
  }
}
